GUIShopTab = class("GUIShopTab", IGUIWindow)

--initTab类型
TabKind = {
    NotKind = 0,
    FitnessEquip = 1,
    Gene = 2,
    Advanced = 3,
    Skill = 4,
}

--选中状态
TabSelectStatus = {
    NotSelect = 1,
    Select = 2,
}

function GUIShopTab:onLoad()
    self.tabId = 0
    self.kind = TabKind.NotKind
    self.selectMode = TabSelectStatus.NotSelect
    self.llTabs = self:getChildWindow(0, GUIType.Layout)
    self.ivTabsBg = self:getChildWindow(0, GUIType.StaticImage, self.llTabs)
    self.ivTabsIcon = self:getChildWindow(0, GUIType.StaticImage, self.ivTabsBg)
    self.tvTabsText = self:getChildWindow(1, GUIType.StaticText, self.ivTabsBg)
end

function GUIShopTab:initTab(TabId, Kind, Bg, Icon, Text)
    self.tabId = TabId
    self.kind = Kind
    self.ivTabsBg:SetImage(Bg)
    self.ivTabsIcon:SetImage(Icon)
    self.tvTabsText:SetText(Lang:getString(Text))
end

function GUIShopTab:changeSelectStatus(Bg, SelectMode)
    self.ivTabsBg:SetImage(Bg)
    self.selectMode = SelectMode
end

return GUIShopTab